@startuml
!theme plain

class "Storage" {
  [C] Storage
  + compressor: Compressor
  + encryptor: Encryptor
  + cacheEngine: CacheEngine
  + useCompression: boolean
  + useEncryption: boolean
  + useCache: boolean
}

class "Compressor" {
  [C] Compressor
  + compress()
}

class "Encryptor" {
  [C] Encryptor
  + encrypt()
}

class "CacheEngine" {
  [C] CacheEngine
  + put()
}

Storage --> Compressor
Storage --> Encryptor
Storage --> CacheEngine

@enduml
